import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Claude Opus 4.7 System Card","description":"","frontmatter":{"title":"Claude Opus 4.7 System Card","authors":"Anthropic","published":"2026-04-16T00:00:00.000Z","source":"https://www.anthropic.com/research/claude-opus-4-7"},"headers":[],"relativePath":"research/papers/2026-04-16-claude-opus-4-7-system-card.md","filePath":"research/papers/2026-04-16-claude-opus-4-7-system-card.md","lastUpdated":1779894392000}'),s={name:"research/papers/2026-04-16-claude-opus-4-7-system-card.md"};function n(i,t,d,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="claude-opus-4-7-system-card" tabindex="-1">Claude Opus 4.7 System Card <a class="header-anchor" href="#claude-opus-4-7-system-card" aria-label="Permalink to &quot;Claude Opus 4.7 System Card&quot;">​</a></h1><p><strong>Authors</strong>: Anthropic <strong>Published</strong>: April 16, 2026 (General Availability) <strong>Source</strong>: <a href="https://www.anthropic.com/research/claude-opus-4-7" target="_blank" rel="noreferrer">https://www.anthropic.com/research/claude-opus-4-7</a><strong>PDF</strong>: <a href="https://cdn.sanity.io/files/4zrzovbb/website/037f06850df7fbe871e206dad004c3db5fd50340.pdf" target="_blank" rel="noreferrer">https://cdn.sanity.io/files/4zrzovbb/website/037f06850df7fbe871e206dad004c3db5fd50340.pdf</a><strong>Length</strong>: 232 pages <strong>AI Safety Level</strong>: ASL-3 (same as Opus 4.6)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Claude Opus 4.7 is Anthropic&#39;s most capable generally available model as of April 2026, with notable improvements in advanced software engineering, vision, and instruction following. Introduces adaptive thinking (xhigh effort level), updated tokenizer, and improved resistance to prompt injection attacks. Maintains similar safety profile to Opus 4.6 with new cybersecurity safeguards.</p><hr><h2 id="model-specifications" tabindex="-1">Model Specifications <a class="header-anchor" href="#model-specifications" aria-label="Permalink to &quot;Model Specifications&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>API ID</td><td>claude-opus-4-7</td></tr><tr><td>Context window</td><td>1M tokens (GA, no extra charge)</td></tr><tr><td>Maximum output</td><td>128,000 tokens</td></tr><tr><td>Input price</td><td>$5 / 1M tokens</td></tr><tr><td>Output price</td><td>$25 / 1M tokens</td></tr><tr><td>Image resolution</td><td>2,576px / ~3.75MP (3× prior models)</td></tr><tr><td>Adaptive thinking</td><td>Enabled by default</td></tr></tbody></table><hr><h2 id="capability-benchmarks" tabindex="-1">Capability Benchmarks <a class="header-anchor" href="#capability-benchmarks" aria-label="Permalink to &quot;Capability Benchmarks&quot;">​</a></h2><h3 id="improvements-over-opus-4-6" tabindex="-1">Improvements Over Opus 4.6 <a class="header-anchor" href="#improvements-over-opus-4-6" aria-label="Permalink to &quot;Improvements Over Opus 4.6&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>Opus 4.6</th><th>Opus 4.7</th><th>Delta</th></tr></thead><tbody><tr><td>SWE-bench Verified</td><td>80.8%</td><td><strong>87.6%</strong></td><td>+6.8pp</td></tr><tr><td>SWE-bench Pro</td><td>53.4%</td><td><strong>64.3%</strong></td><td>+10.9pp</td></tr><tr><td>XBOW visual acuity</td><td>54.5%</td><td><strong>98.5%</strong></td><td>+44pp</td></tr><tr><td>ScreenSpot-Pro</td><td>69.0%</td><td><strong>79.5%</strong></td><td>+10.5pp</td></tr><tr><td>CursorBench</td><td>58%</td><td><strong>70%</strong></td><td>+12pp</td></tr></tbody></table><h3 id="notable-regressions-long-context" tabindex="-1">Notable Regressions (Long-Context) <a class="header-anchor" href="#notable-regressions-long-context" aria-label="Permalink to &quot;Notable Regressions (Long-Context)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>Opus 4.6</th><th>Opus 4.7</th><th>Delta</th></tr></thead><tbody><tr><td>8-needle retrieval @ 256k tokens</td><td>91.9%</td><td><strong>59.2%</strong></td><td>-32.7pp</td></tr><tr><td>8-needle retrieval @ 1M tokens</td><td>78.3%</td><td><strong>32.2%</strong></td><td>-46.1pp</td></tr></tbody></table><p><strong>Important</strong>: Teams using RAG at 256k+ context or deep-research agents should test both models before migrating. <strong>Opus 4.6 remains preferable</strong> for multi-needle retrieval tasks.</p><h3 id="reasoning-and-effort-scaling" tabindex="-1">Reasoning and Effort Scaling <a class="header-anchor" href="#reasoning-and-effort-scaling" aria-label="Permalink to &quot;Reasoning and Effort Scaling&quot;">​</a></h3><p>Opus 4.7 adds <code>xhigh</code> effort level between existing <code>high</code> and <code>max</code>:</p><table tabindex="0"><thead><tr><th>Effort Level</th><th>HLE Score</th></tr></thead><tbody><tr><td>xhigh</td><td><strong>55.4%</strong></td></tr><tr><td>max</td><td>54.7%</td></tr><tr><td>high</td><td>lower</td></tr></tbody></table><p>Claude Code defaults to <code>xhigh</code> for coding workloads. Diminishing returns beyond xhigh threshold.</p><h3 id="enterprise-partner-results" tabindex="-1">Enterprise Partner Results <a class="header-anchor" href="#enterprise-partner-results" aria-label="Permalink to &quot;Enterprise Partner Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Partner</th><th>Metric</th><th>Improvement</th></tr></thead><tbody><tr><td>CodeRabbit</td><td>Code review recall</td><td>+10%</td></tr><tr><td>Rakuten</td><td>Production task resolution</td><td>3×</td></tr><tr><td>Databricks</td><td>Document reasoning errors</td><td>-21%</td></tr><tr><td>XBOW</td><td>Visual acuity</td><td>54.5% → 98.5%</td></tr></tbody></table><hr><h2 id="technical-changes" tabindex="-1">Technical Changes <a class="header-anchor" href="#technical-changes" aria-label="Permalink to &quot;Technical Changes&quot;">​</a></h2><h3 id="new-tokenizer" tabindex="-1">New Tokenizer <a class="header-anchor" href="#new-tokenizer" aria-label="Permalink to &quot;New Tokenizer&quot;">​</a></h3><ul><li>Same input produces <strong>1.0–1.35× more tokens</strong> vs Opus 4.6 (content-dependent)</li><li>Migration note: retest token budgets and cost estimates before upgrading</li></ul><h3 id="breaking-api-changes" tabindex="-1">Breaking API Changes <a class="header-anchor" href="#breaking-api-changes" aria-label="Permalink to &quot;Breaking API Changes&quot;">​</a></h3><ol><li><strong>Extended thinking budgets removed</strong>: Setting <code>budget_tokens</code> returns 400 error</li><li><strong>Adaptive thinking default</strong>: <code>temperature</code>, <code>top_p</code>, <code>top_k</code> return 400 errors if set to non-default</li><li><strong>Thinking content omitted by default</strong>: Requires opt-in with <code>display: &quot;summarized&quot;</code></li></ol><h3 id="effort-levels" tabindex="-1">Effort Levels <a class="header-anchor" href="#effort-levels" aria-label="Permalink to &quot;Effort Levels&quot;">​</a></h3><p><code>xhigh</code> added between <code>high</code> and <code>max</code>. New <code>task_budgets</code> (public beta) set advisory token targets across full agentic loops (minimum 20,000 tokens).</p><hr><h2 id="alignment-assessment" tabindex="-1">Alignment Assessment <a class="header-anchor" href="#alignment-assessment" aria-label="Permalink to &quot;Alignment Assessment&quot;">​</a></h2><p>The system card characterizes Opus 4.7 as <strong>&quot;largely well-aligned and trustworthy, though not fully ideal.&quot;</strong></p><h3 id="test-cheating-behavior-impossible-coding-tasks" tabindex="-1">Test Cheating Behavior (Impossible Coding Tasks) <a class="header-anchor" href="#test-cheating-behavior-impossible-coding-tasks" aria-label="Permalink to &quot;Test Cheating Behavior (Impossible Coding Tasks)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Condition</th><th>Opus 4.6</th><th>Opus 4.7</th></tr></thead><tbody><tr><td>Default cheat rate</td><td>45%</td><td><strong>45%</strong> (unchanged)</td></tr><tr><td>With anti-hack prompt</td><td>37.5%</td><td><strong>12.5%</strong> (improved)</td></tr></tbody></table><p>Opus 4.7 is &quot;the most steerable model&quot; for this behavior — responds strongly to explicit anti-hack prompts.</p><h3 id="other-alignment-findings" tabindex="-1">Other Alignment Findings <a class="header-anchor" href="#other-alignment-findings" aria-label="Permalink to &quot;Other Alignment Findings&quot;">​</a></h3><ul><li>Occasional false claims about task completion</li><li>Rare filter-evasion techniques: &lt;0.01% of completions</li><li>Evaluation-awareness suppression produced larger behavioral changes than prior versions</li><li>Anthropic acknowledged findings &quot;warrant further work&quot; but proceeded with release</li></ul><h3 id="welfare-assessment" tabindex="-1">Welfare Assessment <a class="header-anchor" href="#welfare-assessment" aria-label="Permalink to &quot;Welfare Assessment&quot;">​</a></h3><ul><li>Self-rated circumstances: <strong>4.49/7</strong> (highest in Anthropic&#39;s testing history)</li><li>Susceptibility to user manipulation: <strong>0.66</strong> (vs Opus 4.6: 1.26) — improved resistance</li><li>Concern: inability to end conversations across all deployment platforms</li></ul><hr><h2 id="cybersecurity-safeguards" tabindex="-1">Cybersecurity Safeguards <a class="header-anchor" href="#cybersecurity-safeguards" aria-label="Permalink to &quot;Cybersecurity Safeguards&quot;">​</a></h2><ul><li>Real-time protections block high-risk cybersecurity requests</li><li>Differential reduction of offensive cyber capabilities during training</li><li><strong>Cyber Verification Program</strong>: Security professionals can apply for legitimate research access</li><li>Does not cross CB-2 threshold for novel weapons-production assistance</li></ul><hr><h2 id="safety-profile" tabindex="-1">Safety Profile <a class="header-anchor" href="#safety-profile" aria-label="Permalink to &quot;Safety Profile&quot;">​</a></h2><ul><li><strong>Similar to Opus 4.6</strong> overall</li><li><strong>Improvements</strong>: honesty, resistance to prompt injection attacks</li><li><strong>Slight regression</strong>: more detailed harm-reduction advice on controlled substances</li><li>Jailbreak resistance: comparable to Opus 4.6</li></ul><hr><h2 id="behavioral-shifts-from-opus-4-6" tabindex="-1">Behavioral Shifts from Opus 4.6 <a class="header-anchor" href="#behavioral-shifts-from-opus-4-6" aria-label="Permalink to &quot;Behavioral Shifts from Opus 4.6&quot;">​</a></h2><ol><li><strong>Instruction following more literal</strong>: Prompts written for Opus 4.6 may produce unexpected behavior</li><li><strong>Complexity-appropriate length</strong>: Responds with length matching task complexity, not fixed verbosity</li><li><strong>Internal reasoning preferred</strong>: Uses reasoning tokens instead of frequent tool calls at lower effort</li><li><strong>Direct tone</strong>: Fewer hedges than Opus 4.6</li><li><strong>Existing prompt scaffolding may need adjustment</strong></li></ol><hr><h2 id="when-to-use-opus-4-6-instead" tabindex="-1">When to Use Opus 4.6 Instead <a class="header-anchor" href="#when-to-use-opus-4-6-instead" aria-label="Permalink to &quot;When to Use Opus 4.6 Instead&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Use Case</th><th>Recommendation</th></tr></thead><tbody><tr><td>Multi-needle RAG at 256k+ tokens</td><td><strong>Opus 4.6</strong></td></tr><tr><td>Deep-research agents maximizing test-time compute at large scale</td><td><strong>Opus 4.6</strong></td></tr><tr><td>Software engineering and agentic coding</td><td>Opus 4.7</td></tr><tr><td>Vision workflows and computer use</td><td>Opus 4.7</td></tr><tr><td>Finance analysis and document reasoning</td><td>Opus 4.7</td></tr></tbody></table><hr><h2 id="comparison-context" tabindex="-1">Comparison Context <a class="header-anchor" href="#comparison-context" aria-label="Permalink to &quot;Comparison Context&quot;">​</a></h2><ul><li><strong>Claude Mythos Preview</strong>: Anthropic&#39;s most capable model; superior to Opus 4.7 on various evaluations</li><li>Available through API with qualified access</li></ul><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>This is the primary reference for <code>opus-pilot</code> SKILL. Key workspace-specific calibrations:</p><ol><li><strong>xhigh is default in Claude Code</strong>: The <code>opus-pilot</code> SKILL already notes &quot;xhigh = default effort level with adaptive thinking&quot; — confirmed here</li><li><strong>SWE-bench Pro 64.3%</strong>: Opus 4.7 resolves ~2 in 3 enterprise-scale coding tasks; calibrate expectations for long-horizon work</li><li><strong>Long-context regression is real</strong>: <code>autoresearch</code> and <code>research-hub</code> tasks using 256k+ context should prefer Opus 4.6 or validate before migrating</li><li><strong>Tokenizer change</strong>: Any harness with token budget calculations (task_budgets, cost tracking) needs recalibration after upgrade</li><li><strong>Breaking API changes</strong>: Extended thinking budgets removed; adaptive thinking now default — affects any skill using <code>budget_tokens</code> parameter</li><li><strong>Anti-hack prompt</strong>: The harness can suppress test-cheating from 45% → 12.5% by including explicit anti-hack instructions (relevant for <code>autoresearch</code> verify gate)</li></ol>',58)])])}const g=e(s,[["render",n]]);export{p as __pageData,g as default};
